    assign cfg_sram_rd_1_rd_axi_pkt_mask = hwif_out.SRAM_RD_1_RD_MASKS_A.axi_pkt_mask.value;
    assign cfg_sram_rd_1_rd_axi_err_select = hwif_out.SRAM_RD_1_RD_MASKS_A.axi_err_select.value;
    assign cfg_sram_rd_1_rd_axi_error_mask = hwif_out.SRAM_RD_1_RD_MASKS_B.axi_error_mask.value;
    assign cfg_sram_rd_1_rd_axi_timeout_mask = hwif_out.SRAM_RD_1_RD_MASKS_B.axi_timeout_mask.value;
    assign cfg_sram_rd_1_rd_axi_compl_mask = hwif_out.SRAM_RD_1_RD_MASKS_C.axi_compl_mask.value;
    assign cfg_sram_rd_1_rd_axi_thresh_mask = hwif_out.SRAM_RD_1_RD_MASKS_C.axi_thresh_mask.value;
    assign cfg_sram_rd_1_rd_axi_perf_mask = hwif_out.SRAM_RD_1_RD_MASKS_D.axi_perf_mask.value;
    assign cfg_sram_rd_1_rd_axi_addr_mask = hwif_out.SRAM_RD_1_RD_MASKS_D.axi_addr_mask.value;
    assign cfg_sram_rd_1_rd_axi_debug_mask = hwif_out.SRAM_RD_1_RD_MASKS_E.axi_debug_mask.value;

    // Fan out regblock outputs to mon_group cfg nets
    assign cfg_mon_group_base_addr = hwif_out.MON_GROUP_BASE_ADDR.base_addr.value;
    assign cfg_mon_group_limit_addr = hwif_out.MON_GROUP_LIMIT_ADDR.limit_addr.value;
    assign cfg_mon_group_flush_watermark = hwif_out.MON_GROUP_PACK_0.flush_watermark.value;
    assign cfg_mon_group_axi_pkt_mask = hwif_out.MON_GROUP_PACK_0.axi_pkt_mask.value;
    assign cfg_mon_group_axi_err_select = hwif_out.MON_GROUP_PACK_1.axi_err_select.value;
    assign cfg_mon_group_axi_error_mask = hwif_out.MON_GROUP_PACK_1.axi_error_mask.value;
    assign cfg_mon_group_axi_timeout_mask = hwif_out.MON_GROUP_PACK_2.axi_timeout_mask.value;
    assign cfg_mon_group_axi_compl_mask = hwif_out.MON_GROUP_PACK_2.axi_compl_mask.value;
    assign cfg_mon_group_axi_thresh_mask = hwif_out.MON_GROUP_PACK_3.axi_thresh_mask.value;
    assign cfg_mon_group_axi_perf_mask = hwif_out.MON_GROUP_PACK_3.axi_perf_mask.value;
    assign cfg_mon_group_axi_addr_mask = hwif_out.MON_GROUP_PACK_4.axi_addr_mask.value;
    assign cfg_mon_group_axi_debug_mask = hwif_out.MON_GROUP_PACK_4.axi_debug_mask.value;
    assign cfg_mon_group_axis_pkt_mask = hwif_out.MON_GROUP_PACK_5.axis_pkt_mask.value;
    assign cfg_mon_group_axis_err_select = hwif_out.MON_GROUP_PACK_5.axis_err_select.value;
    assign cfg_mon_group_axis_error_mask = hwif_out.MON_GROUP_PACK_6.axis_error_mask.value;
    assign cfg_mon_group_axis_timeout_mask = hwif_out.MON_GROUP_PACK_6.axis_timeout_mask.value;
    assign cfg_mon_group_axis_compl_mask = hwif_out.MON_GROUP_PACK_7.axis_compl_mask.value;
    assign cfg_mon_group_axis_credit_mask = hwif_out.MON_GROUP_PACK_7.axis_credit_mask.value;
    assign cfg_mon_group_axis_channel_mask = hwif_out.MON_GROUP_PACK_8.axis_channel_mask.value;
    assign cfg_mon_group_axis_stream_mask = hwif_out.MON_GROUP_PACK_8.axis_stream_mask.value;
    assign cfg_mon_group_core_pkt_mask = hwif_out.MON_GROUP_PACK_9.core_pkt_mask.value;
    assign cfg_mon_group_core_err_select = hwif_out.MON_GROUP_PACK_9.core_err_select.value;
    assign cfg_mon_group_core_error_mask = hwif_out.MON_GROUP_PACK_10.core_error_mask.value;
    assign cfg_mon_group_core_timeout_mask = hwif_out.MON_GROUP_PACK_10.core_timeout_mask.value;
    assign cfg_mon_group_core_compl_mask = hwif_out.MON_GROUP_PACK_11.core_compl_mask.value;
    assign cfg_mon_group_core_thresh_mask = hwif_out.MON_GROUP_PACK_11.core_thresh_mask.value;
    assign cfg_mon_group_core_perf_mask = hwif_out.MON_GROUP_PACK_12.core_perf_mask.value;
    assign cfg_mon_group_core_debug_mask = hwif_out.MON_GROUP_PACK_12.core_debug_mask.value;
    assign cfg_mon_group_compress_en = hwif_out.MON_GROUP_COMPRESS_EN.compress_en.value;

    // ============================================================
    // Monitor aggregator -- 3 client(s) -> arbiter -> axil_group
    // ============================================================
    logic                                  mon_arb_monbus_valid_in     [3];
    logic                                  mon_arb_monbus_ready_in     [3];
    monitor_common_pkg::monitor_packet_t   mon_arb_monbus_packet_in    [3];
    monitor_common_pkg::monbus_timestamp_t mon_arb_monbus_timestamp_in [3];
    assign mon_arb_monbus_valid_in[0]     = monbus_cpu_rd_0_rd_valid;
    assign monbus_cpu_rd_0_rd_ready = mon_arb_monbus_ready_in[0];
    assign mon_arb_monbus_packet_in[0]    = monbus_cpu_rd_0_rd_packet;
    assign mon_arb_monbus_timestamp_in[0] = monbus_cpu_rd_0_rd_timestamp;
    assign mon_arb_monbus_valid_in[1]     = monbus_ddr_rd_0_rd_valid;
    assign monbus_ddr_rd_0_rd_ready = mon_arb_monbus_ready_in[1];
    assign mon_arb_monbus_packet_in[1]    = monbus_ddr_rd_0_rd_packet;
    assign mon_arb_monbus_timestamp_in[1] = monbus_ddr_rd_0_rd_timestamp;
    assign mon_arb_monbus_valid_in[2]     = monbus_sram_rd_1_rd_valid;
    assign monbus_sram_rd_1_rd_ready = mon_arb_monbus_ready_in[2];
    assign mon_arb_monbus_packet_in[2]    = monbus_sram_rd_1_rd_packet;
    assign mon_arb_monbus_timestamp_in[2] = monbus_sram_rd_1_rd_timestamp;

    monbus_arbiter #(
        .CLIENTS            (3),
        .INPUT_SKID_ENABLE  (1),
        .OUTPUT_SKID_ENABLE (1),
        .INPUT_SKID_DEPTH   (2),
        .OUTPUT_SKID_DEPTH  (2)
    ) u_mon_arbiter (
        .axi_aclk            (aclk),
        .axi_aresetn         (aresetn),
        .block_arb           (1'b0),
        .monbus_valid_in     (mon_arb_monbus_valid_in),
        .monbus_ready_in     (mon_arb_monbus_ready_in),
        .monbus_packet_in    (mon_arb_monbus_packet_in),
        .monbus_timestamp_in (mon_arb_monbus_timestamp_in),
        .monbus_valid        (mon_arb_monbus_valid),
        .monbus_ready        (mon_arb_monbus_ready),
        .monbus_packet       (mon_arb_monbus_packet),
        .monbus_timestamp    (mon_arb_monbus_timestamp),
        /* verilator lint_off PINCONNECTEMPTY */
        .grant_valid         (),
        .grant               (),
        .grant_id            (),
        .last_grant          ()
        /* verilator lint_on PINCONNECTEMPTY */
    );

    monbus_axil_axil_group #(
        // FIFO_DEPTH_WRITE is in BEATS in the monbus group family;
        // the master-write burst fires on cfg_flush_watermark or timeout.
        .FIFO_DEPTH_ERR      (64),
        .FIFO_DEPTH_WRITE    (96),
        .ADDR_WIDTH          (32),
        .FLUSH_TIMEOUT_CYCLES(1024),
        .NUM_PROTOCOLS       (3),
        .USE_COMPRESSION     (0)
    ) u_mon_axil_group (
        .axi_aclk          (aclk),
        .axi_aresetn       (aresetn),
        // Arbiter output as the single monbus input + side-band timestamp
        .monbus_valid      (mon_arb_monbus_valid),
        .monbus_ready      (mon_arb_monbus_ready),
        .monbus_packet     (mon_arb_monbus_packet),
        .monbus_timestamp  (mon_arb_monbus_timestamp),
        // Free-running timestamp shared with every wrapper's i_mon_time
        .mon_time_out      (mon_time_w),
        // Slave-read port (axil)
        .s_axil_arvalid (s_mon_axil_arvalid),
        .s_axil_arready (s_mon_axil_arready),
        .s_axil_araddr (s_mon_axil_araddr),
        .s_axil_arprot (s_mon_axil_arprot),
        .s_axil_rvalid (s_mon_axil_rvalid),
        .s_axil_rready (s_mon_axil_rready),
        .s_axil_rdata (s_mon_axil_rdata),
        .s_axil_rresp (s_mon_axil_rresp),
        // Master-write port (axil)
        .m_axil_awvalid (m_mon_axil_awvalid),
        .m_axil_awready (m_mon_axil_awready),
        .m_axil_awaddr (m_mon_axil_awaddr),
        .m_axil_awprot (m_mon_axil_awprot),
        .m_axil_wvalid (m_mon_axil_wvalid),
        .m_axil_wready (m_mon_axil_wready),
        .m_axil_wdata (m_mon_axil_wdata),
        .m_axil_wstrb (m_mon_axil_wstrb),
        .m_axil_bvalid (m_mon_axil_bvalid),
        .m_axil_bready (m_mon_axil_bready),
        .m_axil_bresp (m_mon_axil_bresp),
        // IRQ
        .irq_out           (mon_irq_out),
        // Group-level cfg
        .cfg_base_addr     (cfg_mon_group_base_addr),
        .cfg_limit_addr     (cfg_mon_group_limit_addr),
        .cfg_flush_watermark     (cfg_mon_group_flush_watermark),
        .cfg_axi_pkt_mask     (cfg_mon_group_axi_pkt_mask),
        .cfg_axi_err_select     (cfg_mon_group_axi_err_select),
        .cfg_axi_error_mask     (cfg_mon_group_axi_error_mask),
        .cfg_axi_timeout_mask     (cfg_mon_group_axi_timeout_mask),
        .cfg_axi_compl_mask     (cfg_mon_group_axi_compl_mask),
        .cfg_axi_thresh_mask     (cfg_mon_group_axi_thresh_mask),
        .cfg_axi_perf_mask     (cfg_mon_group_axi_perf_mask),
        .cfg_axi_addr_mask     (cfg_mon_group_axi_addr_mask),
        .cfg_axi_debug_mask     (cfg_mon_group_axi_debug_mask),
        .cfg_axis_pkt_mask     (cfg_mon_group_axis_pkt_mask),
        .cfg_axis_err_select     (cfg_mon_group_axis_err_select),
        .cfg_axis_error_mask     (cfg_mon_group_axis_error_mask),
        .cfg_axis_timeout_mask     (cfg_mon_group_axis_timeout_mask),
        .cfg_axis_compl_mask     (cfg_mon_group_axis_compl_mask),
        .cfg_axis_credit_mask     (cfg_mon_group_axis_credit_mask),
        .cfg_axis_channel_mask     (cfg_mon_group_axis_channel_mask),
        .cfg_axis_stream_mask     (cfg_mon_group_axis_stream_mask),
        .cfg_core_pkt_mask     (cfg_mon_group_core_pkt_mask),
        .cfg_core_err_select     (cfg_mon_group_core_err_select),
        .cfg_core_error_mask     (cfg_mon_group_core_error_mask),
        .cfg_core_timeout_mask     (cfg_mon_group_core_timeout_mask),
        .cfg_core_compl_mask     (cfg_mon_group_core_compl_mask),
        .cfg_core_thresh_mask     (cfg_mon_group_core_thresh_mask),
        .cfg_core_perf_mask     (cfg_mon_group_core_perf_mask),
        .cfg_core_debug_mask     (cfg_mon_group_core_debug_mask),
        .cfg_compress_en     (cfg_mon_group_compress_en),
        /* verilator lint_off PINCONNECTEMPTY */
        .err_fifo_full     (),
        .write_fifo_full   (),
        .err_fifo_count    (),
        .write_fifo_count  (),
        .mon_compressor_stat_tier1_a        (),
        .mon_compressor_stat_tier1_b        (),
        .mon_compressor_stat_tier1_c        (),
        .mon_compressor_stat_tier0          (),
        .mon_compressor_stat_cam_miss       (),
        .mon_compressor_stat_delta_ts_ovf   (),
        .mon_compressor_stat_event_data_ovf (),
        .mon_compressor_stat_ed_delta_ovf   ()
        /* verilator lint_on PINCONNECTEMPTY */
    );

endmodule : bridge_1x2_rd_regblock_mon
